349         unsigned NumElts = FVTy->getNumElements();
350         assert(NumElts != 0 && "Constant vector with no elements?");
351         bool HasNonUndefElements = false;
352         for (unsigned i = 0; i != NumElts; ++i) {
353           Constant *Elt = C->getAggregateElement(i);
